import { useState, useEffect } from "react";

// ============================================================
// DATA
// ============================================================
const SITES = Array.from({ length: 44 }, (_, i) => ({
  id: i + 1,
  name: `فيلا ${100 + i + 1}`,
  plot: `9141${2000 + i}`,
  engineer: ["أحمد هارون", "محمد النجار", "محمد موسى"][i % 3],
  progress: [26, 45, 60, 72, 35, 18, 90, 55, 40, 80, 22, 65, 48, 33, 77, 12, 58, 42, 88, 30,
    50, 68, 15, 95, 37, 62, 25, 73, 44, 85, 19, 56, 38, 70, 28, 82, 47, 20, 64, 91, 34, 59, 76, 43][i],
  status: i > 41 ? "مكتمل" : i % 5 === 0 ? "متوقف" : "جارٍ التنفيذ",
  issues: i % 7 === 0 ? ["تأخر توريد الحديد", "انتظار اعتماد المستشار"] : i % 9 === 0 ? ["نقص عمالة"] : [],
}));

const MATERIAL_REQUESTS = [
  { id: "MR-001", site: "فيلا 101", material: "حديد تسليح Ø16", qty: 5, unit: "طن", requestedBy: "أحمد هارون", date: "2026-06-10", status: "موردة", phase: "توريد" },
  { id: "MR-002", site: "فيلا 115", material: "خشب كونتر 18مم", qty: 120, unit: "م²", requestedBy: "محمد النجار", date: "2026-06-15", status: "أمر شراء", phase: "أمر شراء" },
  { id: "MR-003", site: "فيلا 118", material: "بلوك خرساني 20×20×40", qty: 2000, unit: "قطعة", requestedBy: "محمد موسى", date: "2026-06-18", status: "عرض سعر", phase: "عرض سعر" },
  { id: "MR-004", site: "فيلا 120", material: "أسمنت بورتلاند", qty: 50, unit: "كيس", requestedBy: "أحمد هارون", date: "2026-06-20", status: "اعتماد", phase: "اعتماد" },
  { id: "MR-005", site: "فيلا 103", material: "رمل ناعم", qty: 10, unit: "م³", requestedBy: "محمد النجار", date: "2026-06-21", status: "طلب", phase: "طلب" },
  { id: "MR-006", site: "فيلا 110", material: "دهان أبيض خارجي", qty: 300, unit: "لتر", requestedBy: "محمد موسى", date: "2026-06-22", status: "ناقص", phase: "صرف" },
  { id: "MR-007", site: "فيلا 105", material: "بلاط سيراميك 60×60", qty: 450, unit: "م²", requestedBy: "أحمد هارون", date: "2026-06-19", status: "أمر شراء", phase: "أمر شراء" },
  { id: "MR-008", site: "فيلا 112", material: "مواسير PVC 4 بوصة", qty: 80, unit: "طول", requestedBy: "محمد النجار", date: "2026-06-17", status: "موردة", phase: "توريد" },
];

