  "طلب": "#6B7280",
  "عرض سعر": "#F59E0B",
  "اعتماد": "#3B82F6",
  "أمر شراء": "#8B5CF6",
  "توريد": "#10B981",
  "صرف": "#1B2A4A",
  "ناقص": "#EF4444",
  "موردة": "#10B981",
};

const STATUS_COLOR = { "جارٍ التنفيذ": "#10B981", "متوقف": "#EF4444", "مكتمل": "#6B7280" };
const TYPE_ICON = { "رسالة": "✉️", "تقرير تقدم": "📊", "أمر تغيير": "🔄", "رسم هندسي": "📐" };
const ROLE_COLOR = { "مدير": "#10B981", "مهندس موقع": "#3B82F6", "مشتريات": "#F59E0B" };

// ============================================================
// SHARED COMPONENTS
// ============================================================
const PhaseBar = ({ current }) => {
  const idx = PHASES.indexOf(current);
  return (
    <div style={{ display: "flex", gap: 0, borderRadius: 8, overflow: "hidden", fontSize: 10 }}>
      {PHASES.map((p, i) => (
        <div key={p} style={{
          flex: 1, padding: "4px 1px", textAlign: "center",
          background: i <= idx ? "#1B2A4A" : "#E5E7EB",
          color: i <= idx ? "#B8923C" : "#9CA3AF",
          fontWeight: i === idx ? 700 : 400,
          borderRight: i < PHASES.length - 1 ? "1px solid #fff" : "none",
        }}>{p}</div>
      ))}
    </div>
  );
};

const Badge = ({ label, color }) => (
  <span style={{
    background: color + "20", color, border: `1px solid ${color}40`,
    borderRadius: 20, padding: "2px 10px", fontSize: 11, fontWeight: 600, whiteSpace: "nowrap",
  }}>{label}</span>
);

const Card = ({ children, style = {}, onClick }) => (
  <div onClick={onClick} style={{
    background: "#fff", borderRadius: 12, padding: 16,
    boxShadow: "0 1px 4px rgba(0,0,0,0.08)", marginBottom: 12,
    cursor: onClick ? "pointer" : "default", ...style,
  }}>{children}</div>
);

const StatBox = ({ label, value, color = "#1B2A4A" }) => (
  <div style={{
    background: "#fff", borderRadius: 12, padding: "14px 16px",
    boxShadow: "0 1px 4px rgba(0,0,0,0.08)", flex: 1, minWidth: 0, textAlign: "center",
  }}>
    <div style={{ fontSize: 28, fontWeight: 800, color }}>{value}</div>
    <div style={{ fontSize: 11, color: "#6B7280", marginTop: 2 }}>{label}</div>
  </div>
);

const Btn = ({ children, onClick, variant = "primary", style = {} }) => (
  <button onClick={onClick} style={{
    padding: "9px 16px", border: "none", borderRadius: 8, cursor: "pointer",
    fontSize: 13, fontWeight: 700, fontFamily: "inherit",
    background: variant === "primary" ? "#1B2A4A" : variant === "danger" ? "#FEF2F2" : "#F9FAFB",
    color: variant === "primary" ? "#B8923C" : variant === "danger" ? "#EF4444" : "#374151",
    border: variant !== "primary" ? `1px solid ${variant === "danger" ? "#FECACA" : "#E5E7EB"}` : "none",
    ...style,
  }}>{children}</button>
);

