const SitesList = ({ onSelectSite }) => {
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("الكل");
  const filtered = SITES.filter(s => {
    const matchSearch = s.name.includes(search) || s.engineer.includes(search) || s.plot.includes(search);
    const matchStatus = statusFilter === "الكل" || s.status === statusFilter;
    return matchSearch && matchStatus;
  });

  return (
    <div>
      <div style={{ fontSize: 18, fontWeight: 800, color: "#1B2A4A", marginBottom: 12 }}>
        المواقع ({filtered.length})
      </div>
      <input
        placeholder="🔍 بحث بالاسم أو المهندس أو رقم القطعة..."
        value={search} onChange={e => setSearch(e.target.value)}
        style={{
          width: "100%", padding: "10px 12px", border: "1px solid #D1D5DB",
          borderRadius: 10, fontSize: 13, marginBottom: 10, direction: "rtl",
          boxSizing: "border-box", fontFamily: "inherit",
        }}
      />
      <div style={{ display: "flex", gap: 6, marginBottom: 14 }}>
        {["الكل", "جارٍ التنفيذ", "متوقف", "مكتمل"].map(s => (
          <button key={s} onClick={() => setStatusFilter(s)} style={{
            padding: "5px 12px", border: "none", borderRadius: 20, cursor: "pointer",
            fontSize: 11, fontWeight: 600, fontFamily: "inherit",
            background: statusFilter === s ? "#1B2A4A" : "#E5E7EB",
            color: statusFilter === s ? "#B8923C" : "#374151",
          }}>{s}</button>
        ))}
      </div>
      {filtered.map(s => (
        <div key={s.id} onClick={() => onSelectSite(s)} style={{
          background: "#fff", borderRadius: 12, padding: "14px 16px", marginBottom: 10,
          boxShadow: "0 1px 4px rgba(0,0,0,0.07)", cursor: "pointer",
          borderRight: `4px solid ${STATUS_COLOR[s.status]}`,
        }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div style={{ fontWeight: 700, color: "#1B2A4A", fontSize: 15 }}>{s.name}</div>
            <Badge label={s.status} color={STATUS_COLOR[s.status]} />
          </div>
          <div style={{ fontSize: 12, color: "#6B7280", marginTop: 4 }}>
            👷 {s.engineer} &nbsp;|&nbsp; 📌 {s.plot}
          </div>
          {s.issues.length > 0 && (
            <div style={{ marginTop: 6, fontSize: 11, color: "#EF4444" }}>
              ⚠️ {s.issues[0]}
            </div>
          )}
          <div style={{ marginTop: 8 }}>
            <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, color: "#9CA3AF", marginBottom: 3 }}>
              <span>التقدم</span><span>{s.progress}%</span>
            </div>
            <div style={{ background: "#E5E7EB", borderRadius: 99, height: 6 }}>
              <div style={{ width: `${s.progress}%`, background: "#B8923C", borderRadius: 99, height: 6 }} />
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

