        <div>
          <Card>
            <div style={{ fontWeight: 700, color: "#1B2A4A", marginBottom: 12 }}>معلومات الموقع</div>
            {[
              ["الحالة", <Badge label={site.status} color={STATUS_COLOR[site.status]} />],
              ["المهندس المسؤول", site.engineer],
