              ["نسبة الإنجاز", `${site.progress}%`],
              ["عدد الوثائق", siteDocs.length],
              ["طلبات المواد", siteMaterials.length],
            ].map(([k, v]) => (
              <div key={k} style={{
                display: "flex", justifyContent: "space-between", alignItems: "center",
                padding: "8px 0", borderBottom: "1px solid #F3F4F6", fontSize: 13,
              }}>
                <span style={{ color: "#6B7280" }}>{k}</span>
                <span style={{ fontWeight: 600 }}>{v}</span>
              </div>
            ))}
          </Card>
          {site.issues.length > 0 ? (
            <Card style={{ background: "#FFF7ED", border: "1px solid #FED7AA" }}>
              <div style={{ fontWeight: 700, color: "#92400E", marginBottom: 8 }}>⚠️ مشاكل مفتوحة</div>
              {site.issues.map((issue, i) => (
                <div key={i} style={{ fontSize: 13, color: "#78350F", marginBottom: 4 }}>• {issue}</div>
              ))}
