            <Card><div style={{ color: "#9CA3AF", fontSize: 13, textAlign: "center", padding: "20px 0" }}>لا توجد وثائق لهذا الموقع</div></Card>
          ) : siteDocs.map(d => (
            <Card key={d.id}>
              <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
