                <Btn style={{ flex: 1 }}>عرض</Btn>
                <Btn variant="secondary">تحميل</Btn>
              </div>
            </Card>
          ))}
          <button style={{
            width: "100%", padding: 12, border: "2px dashed #D1D5DB",
            borderRadius: 12, background: "none", color: "#6B7280", cursor: "pointer",
            fontSize: 13, fontFamily: "inherit",
          }}>+ رفع وثيقة جديدة</button>
        </div>
      )}

      {tab === "materials" && (
        <div>
          {siteMaterials.length === 0 ? (
            <Card><div style={{ color: "#9CA3AF", fontSize: 13, textAlign: "center", padding: "20px 0" }}>لا توجد طلبات مواد لهذا الموقع</div></Card>
          ) : siteMaterials.map(r => (
            <Card key={r.id}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 10 }}>
                <div>
                  <div style={{ fontWeight: 700, fontSize: 13 }}>{r.material}</div>
                  <div style={{ fontSize: 11, color: "#9CA3AF", marginTop: 3 }}>{r.qty} {r.unit} • {r.date}</div>
                </div>
                <Badge label={r.phase} color={PHASE_COLOR[r.phase] || "#6B7280"} />
              </div>
              <PhaseBar current={r.phase} />
            </Card>
          ))}
        </div>
      )}
    </div>
  );
