const Procurement = ({ role }) => {
  const [filter, setFilter] = useState("الكل");
  const filters = ["الكل", ...PHASES, "ناقص"];
  const filtered = filter === "الكل" ? MATERIAL_REQUESTS : MATERIAL_REQUESTS.filter(r => r.phase === filter || r.status === filter);

  return (
    <div>
      <div style={{ fontSize: 18, fontWeight: 800, color: "#1B2A4A", marginBottom: 4 }}>المشتريات وطلبات المواد</div>
      <div style={{ fontSize: 12, color: "#9CA3AF", marginBottom: 12 }}>
        {MATERIAL_REQUESTS.length} طلب • {MATERIAL_REQUESTS.filter(r => !["توريد", "صرف"].includes(r.phase)).length} معلق
      </div>

      <div style={{ display: "flex", gap: 6, overflowX: "auto", paddingBottom: 8, marginBottom: 14 }}>
        {filters.map(f => (
          <button key={f} onClick={() => setFilter(f)} style={{
            padding: "6px 14px", border: "none", borderRadius: 20, cursor: "pointer",
            whiteSpace: "nowrap", fontSize: 12, fontWeight: 600, fontFamily: "inherit",
            background: filter === f ? "#1B2A4A" : "#E5E7EB",
            color: filter === f ? "#B8923C" : "#374151",
          }}>{f}</button>
        ))}
      </div>

      {filtered.map(r => (
        <Card key={r.id}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 10 }}>
            <div>
              <div style={{ fontSize: 11, color: "#9CA3AF" }}>{r.id}</div>
              <div style={{ fontWeight: 700, fontSize: 14, color: "#111" }}>{r.material}</div>
              <div style={{ fontSize: 12, color: "#6B7280", marginTop: 2 }}>{r.site} • {r.qty} {r.unit}</div>
              <div style={{ fontSize: 11, color: "#9CA3AF" }}>طلب: {r.requestedBy} • {r.date}</div>
            </div>
            <Badge label={r.status} color={PHASE_COLOR[r.status] || "#6B7280"} />
          </div>
          <PhaseBar current={r.phase} />
          {role !== "مهندس موقع" && r.phase !== "صرف" && (
            <div style={{ display: "flex", gap: 8, marginTop: 12 }}>
              <Btn style={{ flex: 1 }}>✓ المرحلة التالية</Btn>
              <Btn variant="danger">رفض</Btn>
            </div>
          )}
        </Card>
      ))}

      {role === "مهندس موقع" && (
        <button style={{
          width: "100%", padding: 14, background: "#1B2A4A", color: "#B8923C",
          border: "none", borderRadius: 12, fontSize: 14, fontWeight: 700, cursor: "pointer",
          fontFamily: "inherit", marginTop: 4,
        }}>+ طلب مواد جديد</button>
      )}
    </div>
  );
};

