            }}>{TYPE_ICON[d.type] || "📄"}</div>
            <div style={{ flex: 1 }}>
              <div style={{ fontWeight: 700, fontSize: 13 }}>{d.title}</div>
              <div style={{ fontSize: 11, color: "#9CA3AF", marginTop: 2 }}>{d.site} • {d.type} • {d.date}</div>
            </div>
          </div>
          <div style={{ display: "flex", gap: 8, marginTop: 12 }}>
            <Btn style={{ flex: 1 }}>عرض</Btn>
            <Btn variant="secondary">تحميل</Btn>
          </div>
        </Card>
      ))}
      <button style={{
        width: "100%", padding: 14, border: "2px dashed #D1D5DB",
        borderRadius: 12, background: "none", color: "#6B7280", cursor: "pointer",
        fontSize: 13, fontFamily: "inherit", marginTop: 4,
      }}>+ رفع وثيقة جديدة</button>
    </div>
  );
};

// ============================================================
// MAIN APP
// ============================================================
export default function App() {
  const [user, setUser] = useState(null);
  const [screen, setScreen] = useState("dashboard");
  const [selectedSite, setSelectedSite] = useState(null);
  const [installPrompt, setInstallPrompt] = useState(null);
  const [showInstallBanner, setShowInstallBanner] = useState(false);

  useEffect(() => {
    const handler = e => {
      e.preventDefault();
      setInstallPrompt(e);
      setShowInstallBanner(true);
    };
    window.addEventListener("beforeinstallprompt", handler);
    return () => window.removeEventListener("beforeinstallprompt", handler);
  }, []);

  const handleInstall = () => {
    if (installPrompt) {
      installPrompt.prompt();
      installPrompt.userChoice.then(() => {
        setInstallPrompt(null);
        setShowInstallBanner(false);
      });
    }
  };

  if (!user) return <Login onLogin={role => setUser(role)} />;

  const navItems = [
    { key: "dashboard", label: "الرئيسية", icon: "🏠" },
    { key: "sites", label: "المواقع", icon: "🏗️" },
    { key: "procurement", label: "المشتريات", icon: "📦" },
    { key: "docs", label: "الوثائق", icon: "📁" },
  ];

  return (
    <div style={{ fontFamily: "'Cairo', 'Segoe UI', sans-serif", direction: "rtl", background: "#F3F4F6", minHeight: "100vh" }}>
      {/* HEADER */}
      <div style={{
        background: "#1B2A4A", padding: "12px 16px",
        display: "flex", justifyContent: "space-between", alignItems: "center",
        position: "sticky", top: 0, zIndex: 100,
      }}>
        <div style={{ color: "#B8923C", fontWeight: 800, fontSize: 16 }}>🏗️ Capital Homes</div>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <Badge label={user} color={ROLE_COLOR[user] || "#6B7280"} />
          <button onClick={() => { setUser(null); setScreen("dashboard"); setSelectedSite(null); }} style={{
            background: "none", border: "1px solid #374151", color: "#9CA3AF",
            borderRadius: 6, padding: "4px 8px", cursor: "pointer", fontSize: 11, fontFamily: "inherit",
          }}>خروج</button>
        </div>
      </div>

      {/* PWA INSTALL BANNER */}
      {showInstallBanner && (
        <div style={{
          background: "#B8923C", padding: "10px 16px",
          display: "flex", justifyContent: "space-between", alignItems: "center",
        }}>
          <div style={{ fontSize: 13, color: "#1B2A4A", fontWeight: 700 }}>
            📲 نزّل الأبلكيشن على موبايلك
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={handleInstall} style={{
              background: "#1B2A4A", color: "#B8923C", border: "none",
              borderRadius: 8, padding: "6px 14px", fontSize: 12,
              fontWeight: 700, cursor: "pointer", fontFamily: "inherit",
            }}>تنزيل</button>
            <button onClick={() => setShowInstallBanner(false)} style={{
              background: "none", color: "#1B2A4A", border: "none",
              fontSize: 18, cursor: "pointer", lineHeight: 1,
            }}>✕</button>
          </div>
        </div>
      )}

      {/* CONTENT */}
      <div style={{ padding: "16px 16px 80px" }}>
        {screen === "dashboard" && <Dashboard role={user} />}
        {screen === "sites" && !selectedSite && (
          <SitesList onSelectSite={s => setSelectedSite(s)} />
        )}
        {screen === "sites" && selectedSite && (
          <SiteDetail site={selectedSite} onBack={() => setSelectedSite(null)} />
        )}
        {screen === "procurement" && <Procurement role={user} />}
        {screen === "docs" && <Documents />}
      </div>

      {/* BOTTOM NAV */}
      <div style={{
        position: "fixed", bottom: 0, left: 0, right: 0,
        background: "#fff", borderTop: "1px solid #E5E7EB",
        display: "flex", zIndex: 100,
      }}>
        {navItems.map(item => (
          <button key={item.key} onClick={() => { setScreen(item.key); setSelectedSite(null); }} style={{
            flex: 1, padding: "10px 4px 8px", border: "none", background: "none",
            cursor: "pointer", display: "flex", flexDirection: "column", alignItems: "center",
            gap: 2, fontFamily: "inherit",
          }}>
            <span style={{ fontSize: 20 }}>{item.icon}</span>
            <span style={{ fontSize: 10, fontWeight: 600, color: screen === item.key ? "#1B2A4A" : "#9CA3AF" }}>
              {item.label}
            </span>
            {screen === item.key && (
              <div style={{ width: 20, height: 3, background: "#B8923C", borderRadius: 99 }} />
            )}
          </button>
        ))}
      </div>
    </div>
  );
}
